<?php namespace App\Services\Inventory; use App\Models\Inventory\StockItem; use App\Models\Inventory\StockJournal; use Illuminate\Support\Facades\DB; class StockService { public function addStock($itemId, $storeId, $qty, $reason) { return DB::transaction(function () use ($itemId, $storeId, $qty, $reason) { $item = StockItem::findOrFail($itemId); $item->increment('stock_qty', $qty); StockJournal::create(['stock_item_id' => $itemId, 'to_store_id' => $storeId, 'type' => 'ADD', 'quantity' => $qty, 'reason' => $reason, 'created_by' => auth()->id()]); }); } public function transfer($itemId, $fromStore, $toStore, $qty) { return DB::transaction(function () use ($itemId, $fromStore, $toStore, $qty) { $item = StockItem::findOrFail($itemId); if ($item->stock_qty < $qty) throw new \Exception('Insufficient stock'); $item->decrement('stock_qty', $qty); $item->increment('stock_qty', $qty); StockJournal::create(['stock_item_id' => $itemId, 'from_store_id' => $fromStore, 'to_store_id' => $toStore, 'type' => 'TRANSFER', 'quantity' => $qty, 'created_by' => auth()->id()]); }); } }
